const _ = require('lodash');
const problemsData = require('../../data/problems.json');

/**
 * Service to handle problems retrieval and filtering.
 */
class ProblemsService {
  /**
   * Get problems filtered by difficulty, tags, and limited by count.
   * @param {Object} params - Filtering parameters.
   * @param {string|string[]} [params.tags] - Skill tags to filter by (case-insensitive, comma-separated or array).
   * @param {string} [params.difficulty] - Difficulty filter.
   * @param {number} [params.limit] - Limit number of results.
   * @returns {Object} - Object containing filtered problems and metadata.
   */
  static getProblems(params = {}) {
    let { tags, difficulty, limit } = params;

    // Normalize tags to array of lowercase strings
    let normalizedTags = [];
    if (tags) {
      if (Array.isArray(tags)) {
        normalizedTags = tags
          .filter(t => typeof t === 'string')
          .map(t => t.trim().toLowerCase())
          .filter(t => t.length > 0);
      } else if (typeof tags === 'string') {
        normalizedTags = tags
          .split(',')
          .map(t => t.trim().toLowerCase())
          .filter(t => t.length > 0);
      }
    }

    // Filter problems by difficulty if provided
    let filtered = problemsData;
    if (difficulty && typeof difficulty === 'string') {
      const diffLower = difficulty.toLowerCase();
      filtered = filtered.filter(p => p.difficulty && p.difficulty.toLowerCase() === diffLower);
    }

    // Filter by tags if any
    if (normalizedTags.length > 0) {
      filtered = filtered.filter(problem => {
        if (!problem.tags || !Array.isArray(problem.tags)) return false;
        const problemTagsLower = problem.tags.map(t => t.toLowerCase());
        // Check if problemTagsLower contains all normalizedTags
        return normalizedTags.every(tag => problemTagsLower.includes(tag));
      });
    }

    // Sort problems by stable criteria: difficulty asc, then problemId asc
    filtered = _.orderBy(filtered, [p => p.difficulty.toLowerCase(), 'problemId'], ['asc', 'asc']);

    // Apply limit if provided and valid
    if (limit !== undefined) {
      const limitNum = Number(limit);
      if (!isNaN(limitNum) && limitNum > 0) {
        filtered = filtered.slice(0, limitNum);
      }
    }

    // Compose metadata with normalized tags
    const metadata = {
      tags: normalizedTags
    };

    return {
      problems: filtered,
      metadata
    };
  }
}

module.exports = ProblemsService;
